## Python

In Python, `UniError` variants are raised as exceptions. The exception message contains the variant name and description.

```python
from binaryoptionstoolsuni import PocketOption, Validator

async def safe_trade(api, asset, action, duration, amount):
    try:
        deal = await api.trade(asset, action, duration, amount)
        return deal
    except Exception as e:
        msg = str(e)

        if 'PocketOption' in msg:
            print(f"Platform error (check asset/session): {msg}")
        elif 'Uuid' in msg:
            print(f"Invalid trade ID format: {msg}")
        elif 'Validator' in msg:
            print(f"Bad validator config: {msg}")
        elif 'General' in msg:
            print(f"Invalid argument (e.g. NaN amount): {msg}")
        else:
            print(f"Unexpected error: {msg}")

        return None


async def safe_connect(ssid):
    try:
        api = await PocketOption.init(ssid)
        return api
    except Exception as e:
        print(f"Connection failed: {e}")
        return None


async def safe_validator(pattern):
    try:
        v = Validator.regex(pattern)
        return v
    except Exception as e:
        # UniError::Validator — the regex pattern was invalid
        print(f"Invalid regex: {e}")
        return None


async def safe_result_with_timeout(api, trade_id, timeout_secs=120):
    try:
        deal = await api.result_with_timeout(trade_id, timeout_secs)
        print(f"Result: profit={deal.profit}")
        return deal
    except Exception as e:
        if 'Uuid' in str(e):
            print(f"Malformed trade ID '{trade_id}': {e}")
        else:
            print(f"Trade result error (possibly timed out): {e}")
        return None
```

