suspend fun safeConnect(ssid: String): PocketOption? {
    return try {
        PocketOption.init(ssid)
    } catch (e: UniException.PocketOption) {
        println("Platform error (check session ID): ${e.message}")
        null
    } catch (e: UniException) {
        println("Connection failed: ${e.message}")
        null
    }
}

