    try {
        val deal = api.buy(asset, 60u, 10.0)
        println("Profit: ${deal.profit}")
    } catch (e: UniException.PocketOption) {
        println("Trade rejected by platform: ${e.message}")
    } catch (e: UniException.General) {
        println("Invalid trade arguments: ${e.message}")
    } catch (e: UniException) {
        println("Trade failed: ${e.message}")
    }
}

// Safe validator construction
fun safeValidator(pattern: String): Validator? {
    return try {
        Validator.regex(pattern)
    } catch (e: UniException.Validator) {
        println("Invalid regex pattern '$pattern': ${e.message}")
        null
    }
}

// Safe result with timeout
suspend fun safeResult(api: PocketOption, tradeId: String) {
    try {
        val deal = api.resultWithTimeout(tradeId, 120u)
        println("Deal result: ${deal.profit}")
    } catch (e: UniException.Uuid) {
        println("Malformed trade ID '$tradeId': ${e.message}")
    } catch (e: UniException) {
        println("Result error (possibly timed out): ${e.message}")
    }
}
