UniError.swift:
## Swift

In Swift, `UniError` is thrown as an error conforming to `Error`. Each variant is a case on the `UniError` enum.

```swift
import binaryoptionstoolsuni

// Safe connection
func safeConnect(ssid: String) async -> PocketOption? {
    do {
        return try await PocketOption.init(ssid: ssid)
    } catch let error as UniError {
        switch error {
        case .pocketOption(let msg):
            print("Platform error (check session ID): \(msg)")
        case .binaryOptions(let msg):
            print("Core library error: \(msg)")
        default:
            print("Connection failed: \(error)")
        }
        return nil
    } catch {
        print("Unexpected error: \(error)")
        return nil
    }
}

// Safe trade
func safeTrade(api: PocketOption, asset: String) async {
    do {
        let deal = try await api.buy(asset: asset, time: 60, amount: 10.0)
        print("Profit: \(deal.profit)")
    } catch let error as UniError {
        switch error {
        case .pocketOption(let msg):
            print("Trade rejected by platform: \(msg)")
        case .general(let msg):
            print("Invalid trade arguments: \(msg)")
        default:
            print("Trade failed: \(error)")
        }
    }
}

// Safe validator construction
func safeValidator(pattern: String) -> Validator? {
    do {
        return try Validator.regex(pattern: pattern)
    } catch let error as UniError {
        if case .validator(let msg) = error {
            print("Invalid regex pattern '\(pattern)': \(msg)")
        }
        return nil
    } catch {
        return nil
    }
}

// Safe result with timeout
func safeResult(api: PocketOption, tradeId: String) async {
    do {
        let deal = try await api.resultWithTimeout(id: tradeId, timeoutSecs: 120)
        print("Deal result: \(deal.profit)")
    } catch let error as UniError {
        switch error {
        case .uuid(let msg):
            print("Malformed trade ID '\(tradeId)': \(msg)")
        default:
            print("Result error (possibly timed out): \(error)")
        }
    }
}
```

