UniError.go:
## Go

In Go, errors are returned as standard `error` values. Use type assertions or `errors.As` to inspect the variant.

```go
package main

import (
    "errors"
    "fmt"
    bot "github.com/ChipaDevTeam/BinaryOptionsTools-v2"
)

// Safe connection
func safeConnect(ssid string) (bot.PocketOption, error) {
    api, err := bot.PocketOptionInit(ssid)
    if err != nil {
        var uniErr *bot.UniError
        if errors.As(err, &uniErr) {
            fmt.Printf("UniError [%s]: %s\n", uniErr.Variant(), uniErr.Message())
        } else {
            fmt.Printf("Connection failed: %v\n", err)
        }
        return nil, err
    }
    return api, nil
}

// Safe trade
func safeTrade(api bot.PocketOption, asset string) {
    deal, err := api.Buy(asset, 60, 10.0)
    if err != nil {
        fmt.Printf("Trade error: %v\n", err)
        return
    }
    fmt.Printf("Profit: %f\n", deal.Profit)
}

// Safe validator construction
func safeValidator(pattern string) (bot.Validator, error) {
    v, err := bot.ValidatorRegex(pattern)
    if err != nil {
        fmt.Printf("Invalid regex pattern '%s': %v\n", pattern, err)
        return nil, err
    }
    return v, nil
}

// Safe result with timeout
func safeResult(api bot.PocketOption, tradeId string) {
    deal, err := api.ResultWithTimeout(tradeId, 120)
    if err != nil {
        fmt.Printf("Result error for ID '%s': %v\n", tradeId, err)
        return
    }
    fmt.Printf("Deal result: %f\n", deal.Profit)
}
```

